mapper.insert:
INSERT INTO notice(
    company_id, notice_type, notice_number, content,
    print_time, print_count, send_status, operator_id
) VALUES(
            #{companyId}, #{noticeType}, #{noticeNumber}, #{content},
            #{printTime}, #{printCount}, #{sendStatus}, #{operatorId}
        )

mapper.select:
SELECT * FROM notice
WHERE company_id = #{companyId}
ORDER BY print_time DESC

SELECT * FROM notice
WHERE company_id = #{companyId}

    AND send_status = 0

ORDER BY print_time DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM notice
WHERE company_id = #{companyId}

    AND send_status = 0

SELECT * FROM notice
WHERE notice_type = #{noticeType}
ORDER BY print_time DESC

SELECT * FROM notice
WHERE send_status = #{sendStatus}
ORDER BY print_time DESC

mapper.update:
UPDATE notice
notice_type = #{noticeType}, content = #{content}, print_time = #{printTime}, print_count = #{printCount}, send_status = #{sendStatus}, operator_id = #{operatorId},
WHERE id = #{id}

UPDATE notice
SET print_count = print_count + 1,
    print_time = #{printTime}
WHERE id = #{id}

UPDATE notice
SET send_status = #{sendStatus}
WHERE id = #{id}
